"use client"

import { useState, useEffect } from "react"
import { ChevronLeft, ChevronRight, X } from "lucide-react"
import { Button } from "@/components/ui/button"
import { cn } from "@/lib/utils"

const onboardingSlides = [
  {
    icon: "🐟",
    title: "Fresh Seafood Delivered",
    description: "Get the freshest catch from the ocean delivered straight to your doorstep within 52 hours.",
    bgGradient: "from-primary/20 to-primary/5",
  },
  {
    icon: "✅",
    title: "Quality Guaranteed",
    description: "Every product goes through expert quality checks. 100% chemical-free and hygienically packed.",
    bgGradient: "from-green-500/20 to-green-500/5",
  },
  {
    icon: "🚚",
    title: "Fast & Free Delivery",
    description: "Free delivery on orders above ₹500. Track your order in real-time with live updates.",
    bgGradient: "from-accent/20 to-accent/5",
  },
]

export function OnboardingScreens() {
  const [currentSlide, setCurrentSlide] = useState(0)
  const [showOnboarding, setShowOnboarding] = useState(false)

  useEffect(() => {
    const hasSeenOnboarding = localStorage.getItem("hasSeenOnboarding")
    if (!hasSeenOnboarding) {
      setShowOnboarding(true)
    }
  }, [])

  const handleSkip = () => {
    localStorage.setItem("hasSeenOnboarding", "true")
    setShowOnboarding(false)
  }

  const handleNext = () => {
    if (currentSlide === onboardingSlides.length - 1) {
      handleSkip()
    } else {
      setCurrentSlide(currentSlide + 1)
    }
  }

  const handlePrev = () => {
    if (currentSlide > 0) {
      setCurrentSlide(currentSlide - 1)
    }
  }

  if (!showOnboarding) return null

  const slide = onboardingSlides[currentSlide]

  return (
    <div className="fixed inset-0 z-[90] bg-background flex flex-col">
      {/* Skip button */}
      <div className="absolute top-4 right-4 z-10">
        <Button variant="ghost" size="sm" onClick={handleSkip} className="text-muted-foreground">
          Skip
          <X className="h-4 w-4 ml-1" />
        </Button>
      </div>

      {/* Slide content */}
      <div className={cn("flex-1 flex flex-col items-center justify-center p-8 bg-gradient-to-b", slide.bgGradient)}>
        <div className="w-32 h-32 rounded-full bg-background shadow-lg flex items-center justify-center mb-8 animate-bounce">
          <span className="text-6xl">{slide.icon}</span>
        </div>
        <h2 className="text-2xl md:text-3xl font-bold text-center mb-4">{slide.title}</h2>
        <p className="text-muted-foreground text-center max-w-md text-lg">{slide.description}</p>
      </div>

      {/* Navigation */}
      <div className="p-6 bg-background">
        {/* Dots */}
        <div className="flex justify-center gap-2 mb-6">
          {onboardingSlides.map((_, index) => (
            <button
              key={index}
              onClick={() => setCurrentSlide(index)}
              className={cn(
                "w-2.5 h-2.5 rounded-full transition-all",
                index === currentSlide ? "bg-primary w-8" : "bg-secondary",
              )}
            />
          ))}
        </div>

        {/* Buttons */}
        <div className="flex gap-4">
          {currentSlide > 0 && (
            <Button variant="outline" onClick={handlePrev} className="flex-1 bg-transparent">
              <ChevronLeft className="h-4 w-4 mr-1" />
              Back
            </Button>
          )}
          <Button onClick={handleNext} className="flex-1">
            {currentSlide === onboardingSlides.length - 1 ? "Get Started" : "Next"}
            {currentSlide < onboardingSlides.length - 1 && <ChevronRight className="h-4 w-4 ml-1" />}
          </Button>
        </div>
      </div>
    </div>
  )
}
